import { useState } from "react";
import { 
  X, 
  Calendar, 
  Trash2, 
  Plus, 
  User as UserIcon,
  CheckCircle2,
  Activity,
  History,
  Briefcase
} from "lucide-react";
import type { CRMLead } from "@/types/crm";
import { useCRM } from "@/hooks/useCRM";
import { useUsers } from "@/hooks/useUsers";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { it } from "date-fns/locale";
import { toast } from "sonner";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

type CRMLeadModalProps = {
  leadId: string;
  onClose: () => void;
};

export function CRMLeadModal({ leadId, onClose }: CRMLeadModalProps) {
  const crm = useCRM();
  const lead = crm.leads.find((item) => item.id === leadId);

  if (!lead) return null;

  return <CRMLeadModalContent key={lead.id} lead={lead} leadId={leadId} onClose={onClose} crm={crm} />;
}

function CRMLeadModalContent({
  lead,
  leadId,
  onClose,
  crm,
}: CRMLeadModalProps & { lead: CRMLead; crm: ReturnType<typeof useCRM> }) {
  const { data: users } = useUsers();
  const [editData, setEditData] = useState<Partial<CRMLead>>(() => lead);
  const [newActivity, setNewActivity] = useState({ tipo: 'Nota', descrizione: '' });

  const handleSave = async () => {
    try {
      await crm.updateLead.mutateAsync({ id: leadId, data: editData });
      toast.success("Lead aggiornato");
    } catch (err) {
      toast.error("Errore durante il salvataggio");
    }
  };

  const handleAddActivity = async () => {
    if (!newActivity.descrizione) return;
    try {
      await crm.addActivity.mutateAsync({ lead_id: leadId, data: newActivity });
      setNewActivity({ tipo: 'Nota', descrizione: '' });
    } catch (err) {
      toast.error("Errore durante l'invio dell'attivitŕ");
    }
  };

  const isVinto = lead.probabilita_chiusura === 100;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-card/60 w-full max-w-5xl max-h-[90vh] rounded-3xl border border-white/5 shadow-2xl flex flex-col overflow-hidden backdrop-blur-2xl">
        {/* Header */}
        <div className="p-6 border-b border-white/5 flex items-center justify-between bg-white/5">
          <div className="flex items-center gap-4">
            <div className="h-12 w-12 rounded-2xl bg-primary/10 flex items-center justify-center">
              <Briefcase className="h-6 w-6 text-primary" />
            </div>
            <div>
              <h2 className="text-xl font-black text-white">{lead.nome_azienda}</h2>
              <div className="flex items-center gap-2 mt-1">
                <Badge className="bg-white/5 text-[#64748b] border-none text-[10px] uppercase font-black tracking-widest px-1.5 h-4.5">
                  ID: {leadId.substring(0, 8)}
                </Badge>
                <div className="flex items-center gap-1.5 text-[10px] font-black text-primary uppercase">
                  {lead.stadio?.nome} • {lead.probabilita_chiusura}% Probabilitŕ
                </div>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {!isVinto ? (
              <Button 
                variant="outline" 
                className="bg-emerald-500/10 hover:bg-emerald-500 hover:text-white border-emerald-500/20 text-emerald-500 font-black uppercase text-[10px] tracking-widest px-4"
                onClick={() => crm.convertLeadToClient.mutate(leadId)}
              >
                <CheckCircle2 className="h-3.5 w-3.5 mr-2" />
                Converti in Cliente
              </Button>
            ) : (
              <Badge className="bg-emerald-500/10 text-emerald-500 border-emerald-500/20 font-black uppercase text-[10px] px-3 h-8">
                Giŕ Convertito
              </Badge>
            )}
            <Button 
              variant="ghost" 
              size="icon" 
              onClick={onClose}
              className="h-10 w-10 text-slate-400 hover:text-white hover:bg-white/5 rounded-full"
            >
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Left Side: Info & Form */}
          <div className="flex-1 p-8 overflow-y-auto custom-scrollbar border-r border-white/5">
            <div className="grid grid-cols-2 gap-8">
              <div className="space-y-6">
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Azienda</Label>
                  <Input 
                    value={editData.nome_azienda || ""} 
                    onChange={e => setEditData({ ...editData, nome_azienda: e.target.value })}
                    className="bg-white/5 border-white/5 h-12 rounded-xl focus:ring-primary/20"
                  />
                </div>
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Referente</Label>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[#475569]" />
                    <Input 
                      value={editData.nome_contatto || ""} 
                      onChange={e => setEditData({ ...editData, nome_contatto: e.target.value })}
                      className="bg-white/5 border-white/5 h-12 px-10 rounded-xl"
                    />
                  </div>
                </div>
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Status Lead</Label>
                  <Select 
                    value={editData.stadio_id} 
                    onValueChange={v => setEditData({ ...editData, stadio_id: v })}
                  >
                    <SelectTrigger className="bg-white/5 border-white/5 h-12 rounded-xl">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-[#0f172a] border-white/10 rounded-xl">
                      {crm.stages.map(s => (
                        <SelectItem key={s.id} value={s.id} className="text-white hover:bg-primary/10">
                          {s.nome} ({s.probabilita}%)
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="space-y-6">
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Valore Stimato (€)</Label>
                  <Input 
                    type="number"
                    value={editData.valore_stimato || 0} 
                    onChange={e => setEditData({ ...editData, valore_stimato: Number(e.target.value) })}
                    className="bg-white/5 border-white/5 h-12 rounded-xl"
                  />
                </div>
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Prossimo Followup</Label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-[#475569]" />
                    <Input 
                      type="date"
                      value={editData.data_prossimo_followup || ""} 
                      onChange={e => setEditData({ ...editData, data_prossimo_followup: e.target.value })}
                      className="bg-white/5 border-white/5 h-12 px-10 rounded-xl"
                    />
                  </div>
                </div>
                <div>
                  <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Fonte</Label>
                  <Input 
                    value={editData.fonte || ""} 
                    onChange={e => setEditData({ ...editData, fonte: e.target.value })}
                    className="bg-white/5 border-white/5 h-12 rounded-xl"
                    placeholder="E.g. LinkedIn, Referral, Sito Web"
                  />
                </div>
              </div>

              <div className="col-span-2">
                <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Assegnato a</Label>
                <div className="flex flex-wrap gap-2">
                  {users?.map(u => (
                    <button
                      key={u.id}
                      onClick={() => setEditData({ ...editData, assegnato_a_id: u.id })}
                      className={`px-3 py-2 rounded-xl border text-xs font-bold transition-all flex items-center gap-2 ${
                        editData.assegnato_a_id === u.id 
                          ? 'bg-primary/20 border-primary text-primary' 
                          : 'bg-white/5 border-white/5 text-[#64748b] hover:bg-white/10'
                      }`}
                    >
                      <div className="h-5 w-5 rounded-full bg-primary/20 flex items-center justify-center text-[8px]">
                        {u.nome.charAt(0)}
                      </div>
                      {u.nome} {u.cognome}
                    </button>
                  ))}
                </div>
              </div>

              <div className="col-span-2">
                <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] mb-2 block">Note Lead</Label>
                <Textarea 
                  value={editData.note || ""} 
                  onChange={e => setEditData({ ...editData, note: e.target.value })}
                  className="bg-white/5 border-white/5 min-h-[120px] rounded-2xl resize-none"
                  placeholder="Dettagli sulle necessitŕ del cliente, budget, tempistiche..."
                />
              </div>
            </div>

            <div className="mt-12 pt-8 border-t border-white/5 flex items-center justify-between">
              <Button 
                variant="ghost" 
                className="text-red-500 hover:text-red-600 hover:bg-red-500/10 font-bold px-6 h-12 rounded-xl"
                onClick={() => {
                  if (confirm("Eliminare definitivamente questo lead?")) {
                    crm.deleteLead.mutate(leadId);
                    onClose();
                  }
                }}
              >
                <Trash2 className="h-4 w-4 mr-2" />
                Elimina Lead
              </Button>
              <Button 
                onClick={handleSave}
                className="bg-primary hover:bg-primary/90 text-white font-black uppercase tracking-widest px-8 h-12 rounded-xl shadow-lg shadow-primary/20"
              >
                Salva Modifiche
              </Button>
            </div>
          </div>

          {/* Right Side: Activity Timeline */}
          <div className="w-[380px] bg-white/5 flex flex-col">
            <div className="p-6 border-b border-white/5">
              <h3 className="text-xs font-black uppercase tracking-widest text-white flex items-center gap-2">
                <History className="h-4 w-4 text-primary" />
                Timeline Attivitŕ
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
              <div className="space-y-6">
                {/* Add New Activity */}
                <div className="p-4 bg-white/5 border border-white/5 rounded-2xl space-y-4">
                  <div className="flex gap-2">
                    {['Nota', 'Chiamata', 'Email', 'Meeting'].map(t => (
                      <button
                        key={t}
                        onClick={() => setNewActivity({ ...newActivity, tipo: t })}
                        className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${
                          newActivity.tipo === t 
                            ? 'bg-primary text-white' 
                            : 'bg-white/5 text-[#475569] hover:bg-white/10'
                        }`}
                      >
                        {t}
                      </button>
                    ))}
                  </div>
                  <Textarea 
                    value={newActivity.descrizione}
                    onChange={e => setNewActivity({ ...newActivity, descrizione: e.target.value })}
                    placeholder="Cosa č successo?"
                    className="bg-transparent border-none p-0 focus-visible:ring-0 text-sm resize-none h-20 scrollbar-hide"
                  />
                  <div className="flex justify-end">
                    <Button 
                      size="sm" 
                      onClick={handleAddActivity}
                    >
                      <Plus className="h-3.5 w-3.5 mr-2" />
                      Aggiungi
                    </Button>
                  </div>
                </div>

                {/* Timeline Items */}
                <div className="space-y-6">
                  {lead.attivita?.sort((a,b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()).map((act, i) => (
                    <div key={i} className="relative pl-6 before:absolute before:left-0 before:top-2 before:bottom-[-24px] before:w-[1px] before:bg-white/10 last:before:hidden">
                      <div className="absolute left-[-4px] top-2 h-2 w-2 rounded-full bg-primary" />
                      <div className="text-[10px] font-black text-primary uppercase mb-1 flex items-center justify-between">
                        {act.tipo}
                        <span className="text-[#475569] font-medium lowercase">
                          {format(new Date(act.created_at), "d MMM, HH:mm", { locale: it })}
                        </span>
                      </div>
                      <p className="text-sm text-slate-300 leading-relaxed">
                        {act.descrizione}
                      </p>
                      <div className="mt-2 flex items-center gap-2 text-[10px] text-[#64748b]">
                        <div className="h-4 w-4 rounded-full bg-white/5 flex items-center justify-center text-[6px]">
                          {act.autore_nome?.charAt(0)}
                        </div>
                        {act.autore_nome}
                      </div>
                    </div>
                  ))}

                  {(!lead.attivita || lead.attivita.length === 0) && (
                    <div className="text-center py-12">
                      <div className="h-12 w-12 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-4">
                        <Activity className="h-6 w-6 text-[#1e293b]" />
                      </div>
                      <p className="text-xs text-[#475569] font-black uppercase tracking-widest">Nessuna attivitŕ registrata</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogFooter 
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { useClienti } from "@/hooks/useClienti";
import { useFornitori } from "@/hooks/useFornitori";
import { useCreateFattura, useUpdateFattura } from "@/hooks/useFatture";
import { toast } from "sonner";
import { 
  Plus, 
  Trash2, 
  FileText, 
  Calendar,
  Building2,
  Receipt
} from "lucide-react";
import { Separator } from "@/components/ui/separator";

interface FatturaModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: "attive" | "passive";
  fattura?: any; // If provided, we are in edit mode
}

type FatturaItem = {
  description: string;
  qty: number;
  price: number;
  amount: number;
};

type FatturaFormData = {
  numero: string;
  data_emissione: string;
  data_scadenza: string;
  cliente_id: string;
  fornitore_id: string;
  importo_netto: number;
  importo_iva: number;
  importo_totale: number;
  stato_pagamento: string;
  valuta: string;
  items: FatturaItem[];
};

function getEmptyFatturaFormData(): FatturaFormData {
  return {
    numero: "",
    data_emissione: new Date().toISOString().split('T')[0],
    data_scadenza: "",
    cliente_id: "",
    fornitore_id: "",
    importo_netto: 0,
    importo_iva: 0,
    importo_totale: 0,
    stato_pagamento: "ATTESA",
    valuta: "EUR",
    items: [],
  };
}

function getInitialFatturaFormData(fattura?: any): FatturaFormData {
  if (!fattura) {
    return getEmptyFatturaFormData();
  }

  return {
    ...getEmptyFatturaFormData(),
    ...fattura,
    data_emissione: fattura.data_emissione ? fattura.data_emissione.split('T')[0] : "",
    data_scadenza: fattura.data_scadenza ? fattura.data_scadenza.split('T')[0] : "",
    items: (fattura.items || fattura.fic_raw_data?.items || []).map((item: any) => ({
      description: item.description || "",
      qty: Number(item.qty || 0),
      price: Number(item.price || 0),
      amount: Number(item.amount || 0),
    })),
  };
}

export function FatturaModal({ open, onOpenChange, type, fattura }: FatturaModalProps) {
  const formKey = fattura?.id ? `edit-${fattura.id}` : `new-${type}`;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      {open ? (
        <FatturaModalForm
          key={formKey}
          onOpenChange={onOpenChange}
          type={type}
          fattura={fattura}
        />
      ) : null}
    </Dialog>
  );
}

function FatturaModalForm({ onOpenChange, type, fattura }: Omit<FatturaModalProps, "open">) {
  const isEdit = !!fattura;
  const isAttiva = type === "attive";

  const { data: clienti = [] } = useClienti();
  const { data: fornitori = [] } = useFornitori();
  const createMutation = useCreateFattura();
  const updateMutation = useUpdateFattura();

  const [formData, setFormData] = useState<FatturaFormData>(() => getInitialFatturaFormData(fattura));

  const handleAddItem = () => {
    const newItems = [...formData.items, { description: "", qty: 1, price: 0, amount: 0 }];
    setFormData({ ...formData, items: newItems });
  };

  const handleRemoveItem = (index: number) => {
    const newItems = formData.items.filter((_, i) => i !== index);
    setFormData({ ...formData, items: newItems });
    recalculateTotals(newItems);
  };

  const handleItemChange = (index: number, field: keyof FatturaItem, value: number | string) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: value };
    
    if (field === "qty" || field === "price") {
      newItems[index].amount = Number(newItems[index].qty || 0) * Number(newItems[index].price || 0);
    }
    
    setFormData({ ...formData, items: newItems });
    recalculateTotals(newItems);
  };

  const recalculateTotals = (items: FatturaItem[]) => {
    const netto = items.reduce((acc, item) => acc + (item.amount || 0), 0);
    const iva = netto * 0.22; // Default 22% VAT for simulation
    setFormData((prev) => ({
      ...prev,
      importo_netto: netto,
      importo_iva: iva,
      importo_totale: netto + iva
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const payload = {
        ...formData,
        importo_totale: Number(formData.importo_totale),
        importo_netto: Number(formData.importo_netto),
        importo_iva: Number(formData.importo_iva),
      };

      if (isEdit) {
        await updateMutation.mutateAsync({ id: fattura.id, type, data: payload });
        toast.success("Fattura aggiornata con successo");
      } else {
        await createMutation.mutateAsync({ type, data: payload });
        toast.success("Fattura creata con successo");
      }
      onOpenChange(false);
    } catch (err) {
      toast.error("Errore durante il salvataggio");
    }
  };

  return (
    <DialogContent className="max-w-4xl bg-card border-border text-white rounded-[32px] overflow-hidden p-0 shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-[6px] bg-gradient-to-r from-primary via-purple-500 to-blue-500" />
        
        <form onSubmit={handleSubmit}>
          <div className="p-8 space-y-8 max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="text-2xl font-black uppercase italic tracking-tighter">
                {isEdit ? "Modifica" : "Nuova"} Fattura <span className="text-primary not-italic">{isAttiva ? "Attiva" : "Passiva"}</span>
              </DialogTitle>
            </DialogHeader>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Main Info */}
              <div className="space-y-6">
                <div className="space-y-4 bg-white/5 p-6 rounded-2xl border border-border/50">
                   <div className="space-y-2">
                      <Label className="text-[10px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                        <FileText className="h-3 w-3" /> Numero Documento
                      </Label>
                      <Input 
                        value={formData.numero} 
                        onChange={(e) => setFormData({...formData, numero: e.target.value})}
                        placeholder="es: 2024/001"
                        className="bg-background/50 border-border focus:ring-primary h-11 font-bold"
                        required
                      />
                   </div>

                   <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] flex items-center gap-2">
                          <Calendar className="h-3 w-3" /> Data Emissione
                        </Label>
                        <Input 
                          type="date"
                          value={formData.data_emissione} 
                          onChange={(e) => setFormData({...formData, data_emissione: e.target.value})}
                          className="bg-background/50 border-border h-11"
                          required
                        />
                      </div>
                      <div className="space-y-2">
                        <Label className="text-[10px] font-black uppercase tracking-widest text-[#475569] flex items-center gap-2">
                          <Calendar className="h-3 w-3" /> Data Scadenza
                        </Label>
                        <Input 
                          type="date"
                          value={formData.data_scadenza} 
                          onChange={(e) => setFormData({...formData, data_scadenza: e.target.value})}
                          className="bg-background/50 border-border h-11"
                        />
                      </div>
                   </div>
                </div>

                <div className="space-y-4 bg-white/5 p-6 rounded-2xl border border-border/50">
                  <div className="space-y-2">
                    <Label className="text-[10px] font-black uppercase tracking-widest text-primary flex items-center gap-2">
                      <Building2 className="h-3 w-3" /> {isAttiva ? "Cliente" : "Fornitore"}
                    </Label>
                    <Select 
                      value={isAttiva ? formData.cliente_id : formData.fornitore_id} 
                      onValueChange={(v) => setFormData({...formData, [isAttiva ? "cliente_id" : "fornitore_id"]: v})}
                    >
                      <SelectTrigger className="bg-background/50 border-border h-11 font-bold">
                        <SelectValue placeholder={`Seleziona ${isAttiva ? "cliente" : "fornitore"}`} />
                      </SelectTrigger>
                      <SelectContent className="bg-card border-border text-white">
                        {isAttiva ? (
                          clienti.map((c: any) => (
                            <SelectItem key={c.id} value={c.id}>{c.ragione_sociale}</SelectItem>
                          ))
                        ) : (
                          fornitori.map((f: any) => (
                            <SelectItem key={f.id} value={f.id}>{f.ragione_sociale}</SelectItem>
                          ))
                        )}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </div>

              {/* Totals & Status */}
              <div className="space-y-6">
                <div className="bg-primary/10 border border-primary/20 p-8 rounded-[2rem] flex flex-col justify-center items-center text-center">
                   <p className="text-[10px] font-black uppercase tracking-[0.2em] text-primary mb-2">Totale Documento</p>
                   <p className="text-5xl font-black text-white tracking-tighter tabular-nums mb-4">
                     {new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(formData.importo_totale)}
                   </p>
                   <div className="flex gap-4 w-full">
                      <div className="flex-1 bg-background/30 p-3 rounded-xl">
                        <span className="text-[8px] font-black uppercase text-[#475569] block">Imponibile</span>
                        <span className="text-sm font-bold text-white">{new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR' }).format(formData.importo_netto)}</span>
                      </div>
                      <div className="flex-1 bg-background/30 p-3 rounded-xl">
