  const { data: timesheets = [] } = useTimesheets({ commessa_id: id });
  const { mutate: updateCommessa, isPending: isUpdating } = useUpdateCommessa();
  const { data: progettiCliente } = useProgetti(commessa?.cliente_id);
  const { user } = useAuth();

  // REAL CLICKUP SYNC Logic
  const { data: clickupData, isLoading: isClickupLoading } = useQuery({
    queryKey: ['clickup-progress', commessa?.cliente?.ragione_sociale],
    queryFn: async () => {
      if (!commessa?.cliente?.ragione_sociale) return null;
      const res = await api.get(`/clickup/progress/${encodeURIComponent(commessa.cliente.ragione_sociale)}`);
      return res.data;
    },
    enabled: !!commessa?.cliente?.ragione_sociale
  });

  const [isPlanningDialogOpen, setIsPlanningDialogOpen] = useState(false);
  const [isContenutoDialogOpen, setIsContenutoDialogOpen] = useState(false);

  const [scopeDraft, setScopeDraft] = useState<{ commessaId: string; value: string } | null>(null);
  const [isAddingProject, setIsAddingProject] = useState(false);
  const [isCreatingProject, setIsCreatingProject] = useState(false);
  const [searchProject, setSearchProject] = useState("");
  const editOreContratto =
    scopeDraft && scopeDraft.commessaId === commessa?.id
      ? scopeDraft.value
      : String(commessa?.ore_contratto ?? 0);

  const oreReali = useMemo(() => {
    const totalMinutes = timesheets.reduce((acc, ts) => acc + ts.durata_minuti, 0);
    return totalMinutes / 60;
  }, [timesheets]);

  const percentualeScope = useMemo(() => {
    if (!commessa || !commessa.ore_contratto || commessa.ore_contratto <= 0) return 0;
    return (oreReali / commessa.ore_contratto) * 100;
  }, [oreReali, commessa]);

  const canEdit = user?.ruolo === "ADMIN" || user?.ruolo === "DEVELOPER" || user?.ruolo === "PM";
  const { data: profitability } = useProfitability(id);
  const { data: taskTemplates = [] } = useTaskTemplates();
  const { data: contenutiCommessa = [] } = useContenuti(id ? { commessa_id: id } : undefined);
  const { mutate: generaTask, isPending: isGenerating } = useGeneraTaskDaTemplate();
  const [selectedTemplateId, setSelectedTemplateId] = useState<string>("");
  const [isAITaskDialogOpen, setIsAITaskDialogOpen] = useState(false);

  const projectTypes = useMemo(
    () => Array.from(new Set((commessa?.righe_progetto || []).map((r) => r.progetto?.tipo).filter(Boolean))).map(String),
    [commessa?.righe_progetto]
  );
  const eligibleTemplates = useMemo(() => {
    const projectTypeSet = new Set(projectTypes);
    return taskTemplates.filter((template) => template.attivo && (!template.progetto_tipo || projectTypeSet.has(template.progetto_tipo)));
  }, [projectTypes, taskTemplates]);

  const aiBudgetOre = useMemo(() => {
    const contracted = Number(commessa?.ore_contratto || 0);
    return contracted > 0 ? contracted : 40;
  }, [commessa?.ore_contratto]);

  const handleUpdateScope = () => {
    if (!id) return;
    updateCommessa({ 
      id, 
      data: { ore_contratto: Number(editOreContratto) } 
    }, {
      onSuccess: () => {
        setScopeDraft(null);
        toast.success("Ore contratto aggiornate con successo");
      },
      onError: () => {
        toast.error("Errore durante l'aggiornamento");
      }
    });
  };

  const handleAddProject = async (progettoId: string) => {
    if (!commessa || !id) return;

    // Check if project already associated
    if (commessa.righe_progetto?.some(r => r.progetto_id === progettoId)) {
        toast.error("Progetto giŕ associato a questa commessa");
        return;
    }

    try {
        const currentRighe = (commessa.righe_progetto || []).map(r => ({
            progetto_id: r.progetto_id,
            importo_fisso: r.importo_fisso,
            importo_variabile: r.importo_variabile,
            delivery_attesa: r.delivery_attesa
        }));

        updateCommessa({
            id: id,
            data: {
                righe_progetto: [...currentRighe, { progetto_id: progettoId }]
            }
        }, {
            onSuccess: () => {
                toast.success("Progetto associato con successo");
                setIsAddingProject(false);
            },
            onError: () => {
                toast.error("Errore durante l'associazione");
            }
        });
    } catch (e) {
        toast.error("Errore imprevisto");
    }
  };

  const handleRemoveProject = async (progettoId: string) => {
    if (!commessa || !id || !confirm("Sicuro di voler rimuovere il progetto da questa commessa?")) return;

    try {
        const newRighe = (commessa.righe_progetto || [])
            .filter(r => r.progetto_id !== progettoId)
            .map(r => ({
                progetto_id: r.progetto_id,
                importo_fisso: r.importo_fisso,
                importo_variabile: r.importo_variabile,
                delivery_attesa: r.delivery_attesa
            }));

        updateCommessa({
            id: id,
            data: { righe_progetto: newRighe }
        }, {
            onSuccess: () => {
                toast.success("Progetto rimosso");
            },
            onError: () => {
                toast.error("Errore durante la rimozione");
            }
        });
    } catch (e) {
        toast.error("Errore imprevisto");
    }
  };

  if (isLoading) {
    return (
      <div className="p-8 space-y-6">
        <div className="h-8 w-48 bg-muted animate-pulse rounded" />
        <div className="grid grid-cols-4 gap-6">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="h-24 bg-card animate-pulse rounded-xl border border-border" />
          ))}
        </div>
      </div>
    );
  }

  if (error || !commessa) {
    return (
      <div className="p-8 text-center">
        <h2 className="text-xl text-white">Commessa non trovata</h2>
        <Button onClick={() => navigate("/commesse")} variant="link" className="text-purple-400">
          Torna alle commesse
        </Button>
      </div>
    );
  }

  const ROI = commessa.costo_manodopera > 0 
    ? ((commessa.valore_fatturabile! - commessa.costo_manodopera) / commessa.costo_manodopera * 100).toFixed(1)
    : "0";

  // Stato machine: sequenza degli stati e transizione successiva
  const STATI_SEQUENZA = ["APERTA", "PRONTA_CHIUSURA", "CHIUSA", "FATTURATA", "INCASSATA"] as const;
  type CommessaStato = typeof STATI_SEQUENZA[number];

  const STATO_LABELS: Record<string, string> = {
    APERTA: "Aperta",
    PRONTA_CHIUSURA: "Pronta Chiusura",
    CHIUSA: "Chiusa",
    FATTURATA: "Fatturata",
    INCASSATA: "Incassata",
  };

  const STATO_COLORS: Record<string, string> = {
    APERTA: "text-blue-400 bg-blue-500/10 border-blue-500/20",
    PRONTA_CHIUSURA: "text-amber-400 bg-amber-500/10 border-amber-500/20",
    CHIUSA: "text-slate-400 bg-slate-500/10 border-slate-500/20",
    FATTURATA: "text-purple-400 bg-purple-500/10 border-purple-500/20",
    INCASSATA: "text-emerald-400 bg-emerald-500/10 border-emerald-500/20",
  };

  const currentStateIndex = STATI_SEQUENZA.indexOf(commessa.stato as CommessaStato);
  const nextState = currentStateIndex < STATI_SEQUENZA.length - 1
    ? STATI_SEQUENZA[currentStateIndex + 1]
    : null;

  const handleAvanzaStato = () => {
    if (!nextState || !id || !canEdit) return;
    updateCommessa(
      { id, data: { stato: nextState } },
      {
        onSuccess: () => toast.success(`Commessa avanzata a: ${STATO_LABELS[nextState]}`),
        onError: () => toast.error("Errore nell'aggiornamento dello stato"),
      }
    );
  };

  const handleRegressoStato = () => {
    const prevState = currentStateIndex > 0 ? STATI_SEQUENZA[currentStateIndex - 1] : null;
    if (!prevState || !id || !canEdit) return;
    if (!confirm(`Sei sicuro di voler tornare a: ${STATO_LABELS[prevState]}?`)) return;
    updateCommessa(
      { id, data: { stato: prevState } },
      {
        onSuccess: () => toast.success(`Commessa retrocessa a: ${STATO_LABELS[prevState]}`),
        onError: () => toast.error("Errore nell'aggiornamento dello stato"),
      }
    );
  };

  const isLocked = ["CHIUSA", "FATTURATA", "INCASSATA"].includes(commessa.stato);

  return (
    <div className="p-8 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* -- BREADCRUMB --------------------------------------- */}
      <nav className="flex items-center gap-2 text-xs text-muted-foreground font-medium">
        <Link to="/commesse" className="hover:text-white transition-colors">Commesse</Link>
        <ChevronRight className="w-3 h-3" />
        {commessa.cliente && (
          <>
            <Link to={`/clienti/${commessa.cliente_id}`} className="hover:text-white transition-colors">
              {commessa.cliente.ragione_sociale}
            </Link>
            <ChevronRight className="w-3 h-3" />
          </>
        )}
        <span className="text-foreground">
          {format(parseISO(commessa.mese_competenza), "MMMM yyyy", { locale: it })}
        </span>
      </nav>

      <div className="flex justify-between items-center">
        <div className="flex items-center gap-4">
          <Button
            variant="ghost"
            onClick={() => navigate("/commesse")}
            className="text-muted-foreground hover:text-white hover:bg-muted"
          >
            <ChevronLeft className="w-4 h-4 mr-2" />
            Indietro
          </Button>
          <div className="h-4 w-px bg-muted" />
          <div className="flex items-center gap-4">
            <ClientAvatar
              name={commessa.cliente?.ragione_sociale || "C"}
              logoUrl={commessa.cliente?.logo_url}
              size="lg"
              className="rounded-xl border-border"
            />
            <div>
              <div className="flex items-center gap-2">
                <h1 className="text-2xl font-bold text-foreground">
                  Commessa {commessa.cliente?.ragione_sociale}
                </h1>
                {isLocked && <Lock className="w-4 h-4 text-muted-foreground" />}
              </div>
              <p className="text-muted-foreground text-sm">
                Competenza: {format(parseISO(commessa.mese_competenza), "MMMM yyyy", { locale: it })}
              </p>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <PDFDownloadLink
            document={<CommessaReportPDF commessa={commessa} timesheets={timesheets} />}
            fileName={`Report_${commessa.cliente?.ragione_sociale}_${commessa.mese_competenza}.pdf`}
          >
            {({ loading }) => (
              <Button
                disabled={loading}
                className="bg-primary hover:bg-primary/90 text-white rounded-xl gap-2 font-black uppercase text-[10px] tracking-widest shadow-[0_0_20px_hsl(var(--primary)/0.2)]"
              >
                <Download className="w-4 h-4" />
                {loading ? "Generazione..." : "Prospetto Mensile"}
              </Button>
            )}
          </PDFDownloadLink>
        </div>
      </div>

      {/* -- STATE MACHINE ------------------------------------ */}
      <Card className="bg-card border-border overflow-hidden">
        <CardContent className="p-6">
          <div className="flex flex-col sm:flex-row items-start sm:items-center gap-6">
            {/* Stato attuale */}
            <div className="flex items-center gap-3 min-w-0">
              <div className={`p-2 rounded-xl border ${STATO_COLORS[commessa.stato]}`}>
                {commessa.stato === "INCASSATA" ? (
                  <CheckCircle2 className="w-5 h-5" />
                ) : isLocked ? (
                  <Lock className="w-5 h-5" />
                ) : (
                  <Unlock className="w-5 h-5" />
                )}
              </div>
              <div>
                <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">Stato Corrente</p>
                <p className={`text-lg font-black ${STATO_COLORS[commessa.stato].split(" ")[0]}`}>
                  {STATO_LABELS[commessa.stato]}
                </p>
              </div>
            </div>

            {/* Progressione stati */}
            <div className="flex-1 flex items-center gap-1 overflow-x-auto pb-1">
              {STATI_SEQUENZA.map((stato, idx) => (
                <React.Fragment key={stato}>
                  <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all ${
                    idx < currentStateIndex
                      ? "bg-emerald-500/10 text-emerald-400 border border-emerald-500/20"
                      : idx === currentStateIndex
                        ? `border ${STATO_COLORS[stato]}`
                        : "bg-muted/30 text-muted-foreground border border-transparent"
                  }`}>
                    {idx < currentStateIndex && <CheckCircle2 className="w-3 h-3" />}
                    {STATO_LABELS[stato]}
                  </div>
                  {idx < STATI_SEQUENZA.length - 1 && (
                    <ArrowRight className={`w-3 h-3 shrink-0 ${idx < currentStateIndex ? "text-emerald-400" : "text-muted-foreground/30"}`} />
                  )}
                </React.Fragment>
              ))}
            </div>

            {/* Azioni stato */}
            {canEdit && (
              <div className="flex items-center gap-2 shrink-0">
                {currentStateIndex > 0 && (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={handleRegressoStato}
                    className="text-muted-foreground hover:text-white text-[10px] font-black uppercase tracking-widest h-9"
                  >
                    <ChevronLeft className="w-3 h-3 mr-1" /> Indietro
                  </Button>
                )}
                {nextState && (
                  <Button
                    size="sm"
                    onClick={handleAvanzaStato}
                    disabled={isUpdating}
                    className="bg-primary/10 border border-primary/30 text-primary hover:bg-primary/20 text-[10px] font-black uppercase tracking-widest h-9 gap-2"
                  >
                    Avanza a {STATO_LABELS[nextState]}
                    <ArrowRight className="w-3 h-3" />
                  </Button>
                )}
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* -- PROFITABILITY ALERT CARD ------------------------- */}
      {profitability && profitability.alert_level !== "NO_DATA" && (
        <Card className={`border overflow-hidden ${
          profitability.alert_level === "CRITICAL"
            ? "border-red-500/30 bg-red-500/5"
            : profitability.alert_level === "WARNING"
              ? "border-amber-500/30 bg-amber-500/5"
              : "border-emerald-500/20 bg-emerald-500/5"
        }`}>
          <CardContent className="p-6">
            <div className="flex flex-col gap-4">
              {/* Header */}
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-xl border ${
                    profitability.alert_level === "CRITICAL"
                      ? "border-red-500/30 bg-red-500/10 text-red-400"
                      : profitability.alert_level === "WARNING"
                        ? "border-amber-500/30 bg-amber-500/10 text-amber-400"
                        : "border-emerald-500/30 bg-emerald-500/10 text-emerald-400"
                  }`}>
                    {profitability.alert_level === "CRITICAL" ? (
                      <AlertCircle className="w-5 h-5" />
                    ) : profitability.alert_level === "WARNING" ? (
                      <TrendingDown className="w-5 h-5" />
                    ) : (
                      <TrendingUp className="w-5 h-5" />
                    )}
                  </div>
                  <div>
                    <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">
                      Marginalitŕ in Tempo Reale
                    </p>
                    <p className={`text-lg font-black ${
                      profitability.alert_level === "CRITICAL"
                        ? "text-red-400"
                        : profitability.alert_level === "WARNING"
                          ? "text-amber-400"
                          : "text-emerald-400"
                    }`}>
                      {profitability.alert_level === "CRITICAL"
                        ? "?? Margine Critico"
                        : profitability.alert_level === "WARNING"
                          ? "Attenzione Margine"
                          : "Margine Sano"}
                    </p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">Margine Attuale</p>
                  <p className={`text-3xl font-black ${
                    profitability.alert_level === "CRITICAL"
                      ? "text-red-400"
                      : profitability.alert_level === "WARNING"
                        ? "text-amber-400"
                        : "text-emerald-400"
                  }`}>
                    {profitability.margine_percentuale}%
                  </p>
                </div>
              </div>

              {/* Progress bar ore */}
              {profitability.ore_budget > 0 && (
                <div className="space-y-1.5">
                  <div className="flex justify-between text-xs text-muted-foreground">
                    <span>Ore consumate: <span className="text-foreground font-semibold">{profitability.ore_consumate.toFixed(1)}h</span></span>
                    <span>Budget: <span className="text-foreground font-semibold">{profitability.ore_budget}h</span></span>
                  </div>
                  <div className="h-2 bg-muted/40 rounded-full overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all ${
                        (profitability.perc_ore_consumate ?? 0) > 100
                          ? "bg-red-500"
                          : (profitability.perc_ore_consumate ?? 0) > 80
                            ? "bg-amber-500"
                            : "bg-emerald-500"
                      }`}
                      style={{ width: `${Math.min(profitability.perc_ore_consumate ?? 0, 100)}%` }}
                    />
                  </div>
                  <p className="text-[10px] text-muted-foreground text-right">{profitability.perc_ore_consumate}% del budget ore utilizzato</p>
                </div>
              )}

              {/* Breakdown finanziario */}
              <div className="grid grid-cols-3 gap-4 pt-2 border-t border-border/50">
                <div>
                  <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">Fatturabile</p>
                  <p className="text-sm font-black text-foreground">€{profitability.valore_fatturabile.toLocaleString("it-IT", { minimumFractionDigits: 0 })}</p>
                </div>
                <div>
                  <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">Costo Manodopera</p>
                  <p className="text-sm font-black text-foreground">€{profitability.costo_manodopera.toLocaleString("it-IT", { minimumFractionDigits: 0 })}</p>
                </div>
                <div>
                  <p className="text-[10px] text-muted-foreground uppercase tracking-widest font-black">Margine €</p>
                  <p className={`text-sm font-black ${profitability.margine_euro >= 0 ? "text-emerald-400" : "text-red-400"}`}>
                    €{profitability.margine_euro.toLocaleString("it-IT", { minimumFractionDigits: 0 })}
                  </p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard
          title="Valore Fatturabile"
          value={`€${commessa.valore_fatturabile?.toLocaleString() || "0"}`} 
          icon={<Euro className="w-5 h-5 text-purple-400" />}
          trend="Totale Entrate"
        />
        <KPICard 
          title="Costo Manodopera" 
          value={`€${commessa.costo_manodopera?.toLocaleString() || "0"}`} 
          icon={<Users className="w-5 h-5 text-blue-400" />}
          trend={`ROI: ${ROI}%`}
          trendPositive={Number(ROI) > 50}
        />
        <KPICard 
          title="Costi Diretti" 
          value={`€${commessa.costi_diretti?.toLocaleString() || "0"}`} 
          icon={<Briefcase className="w-5 h-5 text-amber-400" />}
          trend="Servizi esterni"
        />
        <KPICard 
          title="Margine Lordo" 
          value={`€${commessa.margine_euro?.toLocaleString() || "0"}`} 
          icon={commessa.margine_percentuale! > 30 ? <TrendingUp className="w-5 h-5 text-emerald-400" /> : <TrendingDown className="w-5 h-5 text-red-400" />}
          trend={`${commessa.margine_percentuale}% su fatturato`}
          trendPositive={commessa.margine_percentuale! > 15}
          isPremium
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <Card className="bg-card border-border text-white">
            <CardHeader className="border-b border-border flex flex-row items-center justify-between py-4">
              <CardTitle className="text-lg font-medium flex items-center gap-2">
                <Layers className="w-4 h-4 text-purple-400" />
                Progetti Coinvolti
              </CardTitle>
              <Dialog open={isAddingProject} onOpenChange={setIsAddingProject}>
                <DialogTrigger asChild>
                  <Button variant="outline" size="sm" className="h-8 rounded-xl bg-white/5 border-white/5 text-[10px] font-black uppercase tracking-widest gap-2">
                    <Plus className="w-3.5 h-3.5" /> Associa Progetto
                  </Button>
                </DialogTrigger>
                <DialogContent className="bg-card/95 border-white/10 backdrop-blur-xl p-0 overflow-hidden max-w-md">
                  <DialogHeader className="p-6 pb-0">
                    <DialogTitle className="text-xl font-black italic uppercase italic tracking-tighter">Associa <span className="text-primary not-italic">Progetto</span></DialogTitle>
                  </DialogHeader>
                  <div className="p-6 space-y-4">
                    <div className="relative group">
                       <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[#475569] group-focus-within:text-primary transition-colors" />
                       <Input 
                        placeholder="Cerca progetti del cliente..." 
                        value={searchProject}
                        onChange={e => setSearchProject(e.target.value)}
                        className="pl-10 bg-white/5 border-white/5 h-10 rounded-xl"
                       />
                    </div>
                    <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                       {progettiCliente?.filter(p => p.nome.toLowerCase().includes(searchProject.toLowerCase())).map(p => {
                         const isAssociated = commessa.righe_progetto?.some(r => r.progetto_id === p.id);
                         return (
                           <div 
                            key={p.id} 
                            onClick={() => !isAssociated && handleAddProject(p.id)}
                            className={`flex items-center justify-between p-3 rounded-xl border transition-all cursor-pointer ${
                              isAssociated ? 'bg-emerald-500/10 border-emerald-500/20 opacity-60' : 'bg-white/5 border-white/5 hover:bg-white/10 hover:border-primary/40'
                            }`}
                           >
                             <div className="flex flex-col">
                               <span className="text-xs font-bold text-white">{p.nome}</span>
                               <span className="text-[9px] text-[#475569] font-medium uppercase tracking-widest">{p.tipo}</span>
                             </div>
                             {isAssociated ? <Check className="w-4 h-4 text-emerald-400" /> : <Plus className="w-4 h-4 text-primary" />}
                           </div>
                         );
                       })}
                       {progettiCliente?.length === 0 && (
                         <div className="text-center py-8 text-[#475569] text-xs font-medium italic">Nessun progetto trovato per questo cliente</div>
                       )}
                    </div>
                  </div>
                  <DialogFooter className="p-6 pt-0 flex items-center justify-between gap-4">
                    <Button 
                      onClick={() => {
                        setIsAddingProject(false);
                        setIsCreatingProject(true);
                      }}
                      className="bg-primary/10 border border-primary/20 text-primary hover:bg-primary/20 text-[10px] font-black uppercase tracking-widest px-4 h-10 rounded-xl"
                    >
                      <Plus className="w-3.5 h-3.5 mr-2" /> Crea Nuovo Progetto
                    </Button>
                    <Button variant="ghost" onClick={() => setIsAddingProject(false)} className="text-[10px] font-black uppercase tracking-widest text-[#475569]">Chiudi</Button>
                  </DialogFooter>
                </DialogContent>
              </Dialog>
              <ProgettoDialog 
                open={isCreatingProject} 
                onOpenChange={setIsCreatingProject}
                onSuccess={(newP) => handleAddProject(newP.id)}
              />
            </CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow className="border-border hover:bg-transparent text-muted-foreground">
                    <TableHead className="pl-6 font-medium uppercase text-[10px] tracking-wider">Progetto</TableHead>
                    <TableHead className="font-medium uppercase text-[10px] tracking-wider text-right">Budget Fisso</TableHead>
                    <TableHead className="font-medium uppercase text-[10px] tracking-wider text-right">Budget Var.</TableHead>
                    <TableHead className="font-medium uppercase text-[10px] tracking-wider text-right">Delivery (h)</TableHead>
                    <TableHead className="pr-6 font-medium uppercase text-[10px] tracking-wider text-right">Azioni</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {commessa.righe_progetto?.map((riga: any) => (
                    <TableRow key={riga.id} className="border-border hover:bg-muted/20 group">
                      <TableCell className="pl-6 font-medium text-foreground">
                        <div 
                          className="hover:text-primary cursor-pointer transition-colors"
                          onClick={() => navigate(`/progetti/${riga.progetto_id}`)}
                        >
                          {riga.progetto?.nome || "Progetto Scollegato"}
                        </div>
                        <div className="text-[10px] text-[#475569] uppercase tracking-widest font-black">{riga.progetto?.tipo}</div>
                      </TableCell>
                      <TableCell className="text-right text-foreground font-black tabular-nums">€{Number(riga.importo_fisso).toLocaleString()}</TableCell>
                      <TableCell className="text-right text-foreground font-medium tabular-nums text-[#475569]">€{Number(riga.importo_variabile).toLocaleString()}</TableCell>
                      <TableCell className="text-right text-purple-400 font-black tabular-nums">{riga.delivery_consuntiva} / {riga.delivery_attesa}h</TableCell>
                      <TableCell className="pr-6 text-right">
                         <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Button variant="ghost" size="icon" className="h-8 w-8 rounded-lg hover:bg-white/5 text-[#475569] hover:text-white">
                               <Edit2 className="w-3.5 h-3.5" />
                            </Button>
                            <Button 
                              onClick={() => handleRemoveProject(riga.progetto_id)}
                              variant="ghost" size="icon" className="h-8 w-8 rounded-lg hover:bg-red-500/10 text-[#475569] hover:text-red-500"
                            >
                               <Trash2 className="w-3.5 h-3.5" />
                            </Button>
                         </div>
                      </TableCell>
                    </TableRow>
                  ))}
                  {!commessa.righe_progetto?.length && (
                    <TableRow>
                      <TableCell colSpan={5} className="h-24 text-center text-[#475569]">Nessun progetto associato</TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </CardContent>
          </Card>

          <Card className="bg-card border-border text-white">
            <CardHeader className="border-b border-border">
              <CardTitle className="text-lg font-medium flex items-center gap-2">
                <Clock className="w-4 h-4 text-purple-400" />
                Dettaglio Ore Lavorate
              </CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <Table>
                <TableHeader>
                  <TableRow className="border-border hover:bg-transparent text-muted-foreground">
                    <TableHead className="pl-6 font-medium uppercase text-[10px] tracking-wider">Data</TableHead>
                    <TableHead className="font-medium uppercase text-[10px] tracking-wider">Risorsa</TableHead>
                    <TableHead className="font-medium uppercase text-[10px] tracking-wider">Servizio</TableHead>
                    <TableHead className="pr-6 font-medium uppercase text-[10px] tracking-wider text-right">Durata</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {timesheets.map((ts) => (
                    <TableRow key={ts.id} className="border-border hover:bg-muted/20">
                      <TableCell className="pl-6 text-foreground">{format(parseISO(ts.data_attivita), "dd/MM/yyyy")}</TableCell>
                      <TableCell className="text-foreground">{ts.user?.nome} {ts.user?.cognome}</TableCell>
                      <TableCell className="text-foreground">{ts.task_display_name || ts.servizio || "-"}</TableCell>
                      <TableCell className="pr-6 text-right text-purple-400 font-semibold">
                        {Math.floor(ts.durata_minuti / 60)}h {ts.durata_minuti % 60}m
                      </TableCell>
                    </TableRow>
                  ))}
                  {!timesheets.length && (
                    <TableRow>
                      <TableCell colSpan={4} className="h-24 text-center text-[#475569]">Nessun timesheet associato</TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </div>

        <div className="space-y-6">
          <Card className="bg-card border-primary/20 shadow-xl overflow-hidden">
            <CardHeader className="pb-3 bg-primary/5">
              <CardTitle className="text-xs font-black uppercase tracking-[0.2em] text-primary flex items-center gap-2">
                <CheckCircle2 className="h-4 w-4" />
                Admin Checklist
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-4 space-y-4">
              <div className="space-y-3">
                <ChecklistItem 
                  label="Manodopera (Ore)" 
                  checked={timesheets.length > 0} 
                  subtext={timesheets.length > 0 ? `${oreReali.toFixed(1)}h caricate` : "Nessuna ora caricata"}
                />
                <ChecklistItem 
                  label="Costi Diretti" 
                  checked={(commessa.costi_diretti || 0) > 0} 
                  subtext={(commessa.costi_diretti || 0) > 0 ? `€${commessa.costi_diretti} inseriti` : "Mancano costi software/ads"}
                />
                <ChecklistItem 
                  label="Team Assegnato" 
                  checked={(commessa.righe_progetto || []).every(r => !!r.progetto?.team)} 
                  subtext={(commessa.righe_progetto || []).every(r => !!r.progetto?.team) ? "Team configurato" : "Alcuni progetti senza team"}
                />
                <ChecklistItem 
                  label="Note Progetto" 
                  checked={!!commessa.note && commessa.note.length > 5} 
                  subtext={commessa.note ? "Note inserite" : "Mancano riferimenti"}
                />
              </div>

              {timesheets.length > 0 && 
               (commessa.costi_diretti || 0) > 0 && 
               commessa.note && 
               (commessa.righe_progetto || []).every(r => !!r.progetto?.team) && (
                <div className="p-3 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center gap-2">
                  <Zap className="h-4 w-4 text-emerald-400" />
                  <span className="text-[10px] font-bold text-emerald-400 uppercase tracking-tight">Commessa pronta per chiusura</span>
                </div>
              )}
            </CardContent>
          </Card>

          <Card className="bg-card border-border text-white overflow-hidden">
            <div className={`h-1 bg-gradient-to-r from-purple-500 via-blue-500 to-purple-500`} />
            <CardHeader>
              <CardTitle className="text-lg font-medium">Informazioni Fatturazione</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {commessa.fattura_id ? (
                <div className="p-4 rounded-xl bg-blue-500/5 border border-blue-500/20 space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-xs text-muted-foreground">Fattura N.</span>
                    <span className="text-sm font-bold text-white">{commessa.fattura_numero}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-xs text-muted-foreground">Data Emissione</span>
                    <span className="text-sm text-foreground">{commessa.fattura_data ? format(parseISO(commessa.fattura_data), "dd/MM/yyyy") : "-"}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-xs text-muted-foreground">Importo</span>
                    <span className="text-sm text-emerald-400 font-bold">€{commessa.fattura_importo?.toLocaleString()}</span>
                  </div>
                  <div className="pt-2 border-t border-blue-500/10">
                    <Badge className="w-full justify-center bg-blue-500/20 text-blue-400 hover:bg-blue-500/30">
                      {commessa.fattura_stato || "STATO SCONOSCIUTO"}
                    </Badge>
                  </div>
                </div>
              ) : (
                <div className="p-8 text-center space-y-4 border-2 border-dashed border-border rounded-xl">
                  <FileText className="w-8 h-8 text-[#1e293b] mx-auto" />
                  <p className="text-xs text-muted-foreground">Nessuna fattura collegata.</p>
                  <Button size="sm" variant="outline" className="w-full bg-primary/10 text-purple-400 border-purple-500/20 hover:bg-primary/20">
                    Collega ora
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>

          {/* --- ANALISI VS PIANIFICAZIONE ---------------------- */}
          {commessa.pianificazione && (
            <Card className="bg-card border-border text-white overflow-hidden shadow-[0_0_30px_rgba(139,92,246,0.1)]">
              <div className="h-1 bg-gradient-to-r from-purple-500 to-indigo-500" />
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-black uppercase tracking-widest flex items-center gap-2">
                  <Target className="w-4 h-4 text-purple-400" />
                  Analisi vs Pianificazione
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <ComparisonItem 
                    label="Budget" 
                    planned={Number(commessa.pianificazione.budget)} 
                    actual={Number(commessa.valore_fatturabile)} 
                    symbol="€"
                  />
                  <ComparisonItem 
                    label="Costi Personale" 
                    planned={Number(commessa.pianificazione.costo_totale)} 
                    actual={Number(commessa.costo_manodopera)} 
                    symbol="€"
                    invert
                  />
                  <ComparisonItem 
                    label="Margine" 
                    planned={commessa.pianificazione.margine_percentuale} 
                    actual={commessa.margine_percentuale || 0} 
                    symbol="%"
                  />
                  <ComparisonItem 
                    label="Ore" 
                    planned={Number(commessa.pianificazione.lavorazioni.reduce((acc: any, l: any) => acc + Number(l.ore_previste), 0))} 
                    actual={oreReali} 
                    symbol="h"
                    invert
                  />
                </div>

                <div className="pt-2 border-t border-white/5 flex items-center justify-between">
                  <Badge variant="outline" className="bg-emerald-500/10 text-emerald-400 border-emerald-500/20 text-[9px] font-black uppercase tracking-widest">
                    Target Margine: {commessa.pianificazione.margine_percentuale.toFixed(1)}%
                  </Badge>
                  <Button 
                    variant="ghost" 
                    size="sm" 
                    onClick={() => commessa.pianificazione_id ? navigate(`/pianificazioni/${commessa.pianificazione_id}`) : setIsPlanningDialogOpen(true)}
                    className="h-6 text-[9px] font-black uppercase tracking-widest text-purple-400 hover:text-white hover:bg-purple-500/10"
                  >
                    Apri Piano
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}

          {/* --- CLICKUP PROGRESS ------------------------------ */}
          <Card className="bg-card border-border text-white overflow-hidden">
            <CardHeader className="pb-3 uppercase">
              <CardTitle className="text-[11px] font-black flex items-center gap-2 text-slate-500">
                <div className={`w-2 h-2 rounded-full ${isClickupLoading ? 'bg-slate-500 animate-pulse' : 'bg-[#7b68ee]'}`} />
                Progresso ClickUp
              </CardTitle>
            </CardHeader>
            <CardContent>
              {isClickupLoading ? (
                <div className="space-y-4 animate-pulse">
                   <div className="h-4 w-3/4 bg-muted rounded" />
                   <div className="h-2 w-full bg-muted rounded" />
                </div>
              ) : clickupData?.folder_found ? (
                <div className="space-y-4">
                  <div className="flex justify-between items-end mb-1">
                    <div>
                      <p className="text-xs font-bold text-white">Project Pipeline</p>
                      <p className="text-[10px] text-muted-foreground uppercase tracking-wider">Sync con ClickUp Folder "{commessa.cliente?.ragione_sociale}"</p>
                    </div>
                    <span className="text-lg font-black text-purple-400">{clickupData.percentage}%</span>
                  </div>
                  <div className="h-2 w-full bg-slate-800/50 rounded-full overflow-hidden p-[1px] border border-white/5">
                    <div 
                      className="h-full bg-[#7b68ee] rounded-full shadow-[0_0_10px_rgba(123,104,238,0.4)] transition-all duration-1000" 
                      style={{ width: `${clickupData.percentage}%` }} 
                    />
                  </div>
                  <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-[#475569]">
                    <span>{clickupData.tasks_closed} Task Chiuse</span>
                    <span>{clickupData.tasks_total - clickupData.tasks_closed} Task Aperte</span>
                  </div>
                </div>
              ) : (
                <div className="py-4 text-center border border-dashed border-border rounded-xl">
                  <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">
                    Folder ClickUp non trovato
                  </p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* --- COSTI DIRETTI DETTAGLIO ---------------------- */}
          <CostiDettaglioCard commessaId={id!} />

          {canEdit && (
            <Card className="bg-card border-border text-white overflow-hidden">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-black uppercase tracking-widest flex items-center gap-2">
                  <History className="w-4 h-4 text-primary" />
                  Storico Modifiche
                </CardTitle>
              </CardHeader>
              <CardContent>
                <AuditLogTable tabella="commesse" recordId={commessa.id} hideFilters defaultLimit={8} compact />
              </CardContent>
            </Card>
          )}

          <Card className="bg-card border-border text-white">
            <CardHeader>
              <CardTitle className="text-lg font-medium flex items-center gap-2">
                <Target className="w-4 h-4 text-purple-400" />
                Monitoraggio Scope
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-2">
                <div className="flex justify-between text-xs mb-1">
                  <span className="text-muted-foreground uppercase tracking-wider font-bold">Consumo Ore</span>
                  <span className={`font-black ${percentualeScope >= 100 ? 'text-red-400' : 'text-purple-400'}`}>
                    {oreReali.toFixed(1)} / {commessa.ore_contratto}h
                  </span>
                </div>
                <div className="h-3 w-full bg-muted rounded-full overflow-hidden border border-white/5 p-[1px]">
                  <div 
                    className={`h-full rounded-full transition-all duration-1000 ${
                      percentualeScope >= 100 ? 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]' : 
                      percentualeScope >= 80 ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]' : 
                      'bg-gradient-to-r from-purple-500 to-blue-500'
                    }`}
                    style={{ width: `${Math.min(100, percentualeScope)}%` }}
                  />
                </div>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-[10px] text-muted-foreground uppercase tracking-widest">
                    {percentualeScope.toFixed(1)}% dello scope utilizzato
                  </span>
                  {percentualeScope >= 100 && (
                    <Badge variant="outline" className="bg-red-500/10 text-red-400 border-red-500/20 animate-pulse">
                      SCOPE SUPERATO
                    </Badge>
                  )}
                </div>
              </div>

              <div className="pt-4 border-t border-border">
                <label className="text-[10px] text-muted-foreground uppercase tracking-widest block mb-2">
                  Ore Incluse nel Contratto
                </label>
                <div className="flex gap-2">
                  <Input 
                     type="number" 
                     disabled={!canEdit}
                     value={editOreContratto}
                     onChange={(e) => {
                       if (!commessa) {
                         return;
                       }

                       setScopeDraft({ commessaId: commessa.id, value: e.target.value });
                     }}
                     className="bg-muted border-border text-white text-sm h-9 focus-visible:ring-purple-500/50"
                  />
                  {canEdit && commessa.ore_contratto !== Number(editOreContratto) && (
                    <Button 
                      size="sm" 
                      onClick={handleUpdateScope}
                      disabled={isUpdating}
                      className="bg-purple-600 hover:bg-purple-700 text-white font-bold h-9 px-4 rounded-lg"
                    >
                      {isUpdating ? "..." : "Salva"}
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="bg-card border-border text-white overflow-hidden">
            <CardHeader>
              <CardTitle className="text-lg font-medium">Note Interne</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-foreground whitespace-pre-wrap italic">
                {commessa.note || "Nessuna nota presente."}
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border text-white overflow-hidden">
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between gap-3">
                <CardTitle className="text-lg font-medium">Pipeline Contenuti</CardTitle>
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => navigate(`/contenuti?commessa_id=${commessa.id}`)}
                    className="border-border/50 bg-muted/20 text-xs font-black uppercase tracking-widest"
                  >
                    Vedi board
                    <ArrowRight className="ml-2 h-3.5 w-3.5" />
                  </Button>
                  <Button
                    size="sm"
                    onClick={() => setIsContenutoDialogOpen(true)}
                    className="bg-primary hover:bg-primary/90 text-white text-xs font-black uppercase tracking-widest"
                  >
                    <Plus className="mr-2 h-3.5 w-3.5" />
                    Nuovo
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-3">
              {contenutiCommessa.slice(0, 4).map((contenuto) => (
                <button
                  key={contenuto.id}
                  onClick={() => navigate(`/contenuti?commessa_id=${commessa.id}`)}
                  className="w-full rounded-2xl border border-border/40 bg-muted/10 p-3 text-left hover:border-primary/30 hover:bg-muted/20 transition-colors"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-foreground">{contenuto.titolo}</p>
                      <p className="mt-1 text-xs text-muted-foreground">{contenuto.assegnatario_nome || "Non assegnato"}</p>
                    </div>
                    <Badge variant="outline" className="text-[10px] font-black uppercase tracking-widest">
                      {contenuto.stato.replaceAll("_", " ")}
                    </Badge>
                  </div>
                </button>
              ))}
              {!contenutiCommessa.length && (
                <div className="rounded-2xl border border-dashed border-border/50 p-5 text-sm text-muted-foreground">
                  Nessun contenuto collegato a questa commessa.
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
      {/* -- TASK TEMPLATE SECTION ---------------------------- */}
      {canEdit && id && (
        <Card className="bg-card border-border overflow-hidden">
          <CardHeader className="pb-3 flex flex-row items-center justify-between gap-4">
            <CardTitle className="text-sm font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
              <Layers className="w-4 h-4" />
              Task Generation
            </CardTitle>
            <Button
              onClick={() => setIsAITaskDialogOpen(true)}
              className="bg-primary hover:bg-primary/90 text-white text-xs font-black uppercase tracking-widest gap-1.5 shrink-0"
            >
              <Bot className="w-3.5 h-3.5" />
              Genera con AI
            </Button>
          </CardHeader>
          <CardContent className="space-y-3">
            <p className="text-xs text-muted-foreground">
              Usa un template statico oppure fai generare all'AI una proposta piů contestuale per questo mese.
            </p>
            {eligibleTemplates.length > 0 ? (
              <>
                <div className="flex gap-3">
                  <select
                    value={selectedTemplateId}
                    onChange={(e) => setSelectedTemplateId(e.target.value)}
                    className="flex-1 h-10 rounded-xl border border-border/50 bg-muted/20 text-sm px-3 text-foreground"
                  >
                    <option value="">Seleziona template...</option>
                    {eligibleTemplates.map(t => (
                      <option key={t.id} value={t.id}>
                        {t.nome} ({t.num_items} task)
                      </option>
                    ))}
                  </select>
                  <Button
                    disabled={!selectedTemplateId || isGenerating || !id}
                    onClick={() => {
                      if (selectedTemplateId && id) {
                        generaTask({ templateId: selectedTemplateId, commessaId: id });
                        setSelectedTemplateId("");
                      }
                    }}
                    className="bg-primary hover:bg-primary/90 text-white text-xs font-black uppercase tracking-widest gap-1.5 shrink-0"
                  >
                    <Zap className="w-3.5 h-3.5" />
                    {isGenerating ? "Generando..." : "Da Template"}
                  </Button>
                </div>
                {selectedTemplateId && (() => {
                  const tpl = eligibleTemplates.find(t => t.id === selectedTemplateId);
                  if (!tpl) return null;
                  return (
                    <div className="rounded-xl bg-muted/10 border border-border/20 p-3 space-y-1">
                      <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Preview: {tpl.items.length} task da creare</p>
                      {tpl.items.slice(0, 4).map((item, idx) => (
                        <div key={idx} className="flex items-center gap-2 text-xs text-foreground">
                          <div className="w-1 h-1 rounded-full bg-primary" />
                          {item.titolo}
                          {item.giorno_scadenza && <span className="text-muted-foreground ml-auto">gg{item.giorno_scadenza}</span>}
                        </div>
                      ))}
                      {tpl.items.length > 4 && (
                        <p className="text-[10px] text-muted-foreground">+{tpl.items.length - 4} altri...</p>
                      )}
                    </div>
                  );
                })()}
              </>
            ) : (
              <div className="rounded-xl bg-muted/10 border border-dashed border-border/30 p-4 text-xs text-muted-foreground">
                Nessun template compatibile con i progetti di questa commessa. Puoi comunque generare una proposta con AI.
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {id && commessa && (
        <AITaskGeneratorDialog
          open={isAITaskDialogOpen}
          onOpenChange={setIsAITaskDialogOpen}
          commessaId={id}
          clienteNome={commessa.cliente?.ragione_sociale || "Cliente"}
          meseLabel={commessa.mese_competenza ? format(parseISO(String(commessa.mese_competenza)), "MMMM yyyy", { locale: it }) : "Mese corrente"}
          projectTypes={projectTypes}
          budgetOre={aiBudgetOre}
          defaultProjectId={commessa.righe_progetto?.[0]?.progetto_id}
        />
      )}

      <ContenutoDialog
        open={isContenutoDialogOpen}
        onOpenChange={setIsContenutoDialogOpen}
        defaultCommessaId={id}
      />

      <PlanningDialog
        open={isPlanningDialogOpen}
        onOpenChange={setIsPlanningDialogOpen}
        plan={commessa?.pianificazione}
      />
    </div>
  );
}

function ChecklistItem({ label, checked, subtext }: { label: string; checked: boolean; subtext: string }) {
  return (
    <div className="flex items-start gap-3">
      <div className={cn(
        "mt-0.5 rounded-full p-0.5",
        checked ? "bg-emerald-500/20 text-emerald-500" : "bg-slate-500/20 text-slate-500"
      )}>
        {checked ? <CheckCircle2 className="h-3 w-3" /> : <div className="h-3 w-3" />}
      </div>
      <div className="flex flex-col">
        <span className={cn("text-xs font-bold", checked ? "text-foreground" : "text-faint")}>{label}</span>
        <span className="text-[9px] text-faint uppercase tracking-tighter">{subtext}</span>
      </div>
    </div>
  );
}

