    const costiStruttura = costiFissiList.reduce(
      (total, cost) => total + getAllocatedStructureCost(cost, range),
      0
    );

    return {
      fatturato,
      margineLordo,
      costiStruttura,
      margineNetto: margineLordo - costiStruttura,
